DROP TABLE IF EXISTS apple_varieties;
CREATE TABLE apple_varieties (
    id TEXT PRIMARY KEY,
    name_ja TEXT NOT NULL,
    name_en TEXT,
    name_zh TEXT,
    harvest_season TEXT,
    lineage TEXT,
    origin TEXT,
    official_image_url TEXT,
    summary TEXT,
    description TEXT,
    display_order INTEGER,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

